import type { NextConfig } from "next";

const nextConfig: NextConfig = {};

export default nextConfig;


// lib/db.js
import { unstable_cache } from 'next/cache';

async function loadAllProducts() {
  // Simulate a database read that should be cached between requests.
  await new Promise(resolve => setTimeout(resolve, 100));

  return [
    { id: 1, name: 'Laptop', price: 999, stock: 42, status: 'In stock' },
    { id: 2, name: 'Phone', price: 699, stock: 18, status: 'Low stock' },
    { id: 3, name: 'Tablet', price: 499, stock: 9, status: 'Low stock' },
    { id: 4, name: 'Headphones', price: 199, stock: 76, status: 'In stock' },
    { id: 5, name: 'Watch', price: 299, stock: 0, status: 'Out of stock' }
  ];
}

export const getAllProducts = unstable_cache(loadAllProducts, ['products'], {
  tags: ['products']
});


